text:
Versão Interativa com Observable JS
Responda as perguntas abaixo para obter uma recomendação personalizada:


Ver código R
viewof numVariaveis = Inputs.radio(
  ["1 variável", "2 variáveis", "3 ou mais variáveis"],
  { value: "1 variável", label: "1. Quantas variáveis você deseja visualizar?" }
)









Ver código R
viewof tipoVariavel = {
  if (numVariaveis === "1 variável") {
    return Inputs.radio(
      ["Categórica", "Numérica"],
      { value: "Categórica", label: "2. Qual é o tipo de dados?" }
    );
  }
  if (numVariaveis === "2 variáveis") {
    return Inputs.radio(
      ["Ambas numéricas", "Uma numérica + Uma categórica", "Ambas categóricas", "Temporal (tempo no eixo X)"],
      { value: "Ambas numéricas", label: "2. Qual é a combinação de tipos?" }
    );
  }
  return Inputs.radio(
    ["Usar facets (pequenos múltiplos)", "Usar cor para dimensão extra", "Usar tamanho para dimensão extra"],
    { value: "Usar facets (pequenos múltiplos)", label: "2. Como deseja codificar as variáveis extras?" }
  );
}









Ver código R
viewof detalhe = {
  if (numVariaveis === "1 variável" && tipoVariavel === "Categórica") {
    return Inputs.radio(
      ["2-5 categorias", "Muitas categorias", "Proporção do todo"],
      { value: "2-5 categorias", label: "3. Quantas categorias?" }
    );
  }
  if (numVariaveis === "1 variável" && tipoVariavel === "Numérica") {
    return Inputs.radio(
      ["Mostrar distribuição completa", "Mostrar densidade", "Resumir por grupos"],
      { value: "Mostrar distribuição completa", label: "3. O que deseja mostrar?" }
    );
  }
  return Inputs.radio(["(Não se aplica)"], { value: "(Não se aplica)", label: " " });
}









Ver código R
recomendacao = {
  // 1 variável categórica
  if (numVariaveis === "1 variável" && tipoVariavel === "Categórica") {
    if (detalhe === "2-5 categorias") return { tipo: "Gráfico de Barras", capitulo: "Capítulo 5", descricao: "Use barras verticais para mostrar a frequência de cada categoria.", obs: "Simples, claro e eficaz para a maioria das situações." };
    if (detalhe === "Muitas categorias") return { tipo: "Gráfico de Barras Horizontal", capitulo: "Capítulo 5", descricao: "Barras horizontais dão mais espaço para rótulos longos.", obs: "Ideal quando você tem muitas categorias ou nomes longos." };
    if (detalhe === "Proporção do todo") return { tipo: "Pizza (com ressalvas)", capitulo: "Capítulo 4", descricao: "Gráfico de pizza mostra proporções do todo.", obs: "Cuidado: barras são frequentemente mais claras. Use pizza apenas se houver poucos grupos." };
  }
  // 1 variável numérica
  if (numVariaveis === "1 variável" && tipoVariavel === "Numérica") {
    if (detalhe === "Mostrar distribuição completa") return { tipo: "Histograma", capitulo: "Capítulo 6", descricao: "Mostra a distribuição de uma variável numérica em intervalos (bins).", obs: "Escolha a largura dos bins com cuidado." };
    if (detalhe === "Mostrar densidade") return { tipo: "Gráfico de Densidade", capitulo: "Capítulo 7", descricao: "Versão suavizada do histograma.", obs: "Mais elegante que histograma, melhor para comparações entre grupos." };
    if (detalhe === "Resumir por grupos") return { tipo: "Boxplot", capitulo: "Capítulo 8", descricao: "Mostra quartis, mediana e outliers de uma variável por grupo.", obs: "Compacto e informativo." };
  }
  // 2 variáveis
  if (numVariaveis === "2 variáveis") {
    if (tipoVariavel === "Ambas numéricas") return { tipo: "Scatter Plot", capitulo: "Capítulo 9", descricao: "Mostra a relação entre duas variáveis numéricas.", obs: "Procure correlações, agrupamentos e outliers." };
    if (tipoVariavel === "Uma numérica + Uma categórica") return { tipo: "Boxplot", capitulo: "Capítulo 8", descricao: "Boxplot mostra distribuição completa por grupo.", obs: "Prefira boxplot a barras de médias — mostra mais informação." };
    if (tipoVariavel === "Ambas categóricas") return { tipo: "Barras Agrupadas", capitulo: "Capítulo 5", descricao: "Compara frequências de duas variáveis categóricas.", obs: "Bom para tabelas de contingência." };
    if (tipoVariavel === "Temporal (tempo no eixo X)") return { tipo: "Gráfico de Linha", capitulo: "Capítulo 10", descricao: "Mostra como uma variável muda ao longo do tempo.", obs: "Natural para séries temporais." };
  }
  // 3+ variáveis
  if (numVariaveis === "3 ou mais variáveis") {
    if (tipoVariavel === "Usar facets (pequenos múltiplos)") return { tipo: "Facets / Small Multiples", capitulo: "Capítulos 3 e 5-9", descricao: "Divida em painéis por uma variável categórica.", obs: "Poderoso para visualizar interações." };
    if (tipoVariavel === "Usar cor para dimensão extra") return { tipo: "Scatter ou Barras com Cor", capitulo: "Capítulos 5 e 9", descricao: "Use cor para representar uma variável categórica adicional.", obs: "Máximo 5-7 cores. Cuidado com daltonismo." };
    if (tipoVariavel === "Usar tamanho para dimensão extra") return { tipo: "Scatter com Tamanho (Bubble Chart)", capitulo: "Capítulo 9", descricao: "Use tamanho dos pontos para uma variável numérica adicional.", obs: "A percepção humana de área não é linear." };
  }
  return { tipo: "", capitulo: "", descricao: "", obs: "" };
}









Ver código R
html`
&lt;div style="border: 2px solid #2563EB; padding: 20px; border-radius: 8px; margin-top: 20px; background-color: #DBEAFE;"&gt;
  &lt;h3 style="color: #1D4ED8; margin-top: 0;"&gt;Recomendação&lt;/h3&gt;
  &lt;p&gt;&lt;strong&gt;Tipo de gráfico:&lt;/strong&gt; ${recomendacao.tipo || "Selecione as opções acima"}&lt;/p&gt;
  &lt;p&gt;&lt;strong&gt;Referência:&lt;/strong&gt; ${recomendacao.capitulo}&lt;/p&gt;
  &lt;p&gt;${recomendacao.descricao}&lt;/p&gt;
  &lt;p&gt;&lt;em&gt;${recomendacao.obs}&lt;/em&gt;&lt;/p&gt;
&lt;/div&gt;
`
